class Calc {
    int m_value{};
public:
    void add(int x) { m_value += x; }
};

Calc c;
c.add(5).add(3);  // Error!

class Calc {
    int m_value{};
public:
    Calc&amp; add(int x) { m_value += x; return *this; }
    void print() { std::cout &lt;&lt; m_value; }
};

Calc c;
c.add(5).add(3).print();
